---
const {
  href,
  variant = 'primary',
  size = 'default',
  class: className = '',
  ...rest
} = Astro.props;

const Tag = href ? 'a' : 'button';

const baseClasses = 'inline-flex items-center justify-center font-medium rounded-[14px] transition-all duration-300 no-underline cursor-pointer border-none';

const variants = {
  primary: 'bg-rust text-white hover:bg-rust-dark',
  secondary: 'bg-blue text-white hover:bg-blue/90',
  outline: 'bg-transparent text-rust border-2 border-rust hover:bg-rust hover:text-white',
  dark: 'bg-dark text-white hover:bg-dark/90',
};

const sizes = {
  small: 'px-5 py-2.5 text-sm',
  default: 'px-[37px] py-[15px] text-base',
  large: 'px-[37px] py-[18px] text-lg',
};

const classes = `${baseClasses} ${variants[variant]} ${sizes[size]} ${className}`;
---

<Tag href={href} class={classes} {...rest}>
  <slot />
</Tag>
```

